// Define a struct to represent a Stock
struct Stock {
    let symbol: String
    var price: Double
}

// Define a class to manage the portfolio
class PortfolioManager {
    private(set) var stocks: [Stock] = []

    func addStock(_ stock: Stock) {
        if let index = stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            stocks[index].price = stock.price
        } else {
            stocks.append(stock)
        }
    }

    func removeStock(symbol: String) {
        stocks.removeAll { $0.symbol == symbol }
    }

    func totalValue() -> Double {
        return stocks.reduce(0) { $0 + ($1.price * 100) } // Assuming holding 100 shares of each stock
    }
}

