class StockAPIManager {
    private let apiKey = "YOUR_API_KEY"
    
    func fetchStockPrice(for symbol: String, completion: @escaping (Double?) -> Void) {
        let url = "https://api.iextrading.com/1.0/stock/\(symbol)/quote/latestPrice"
        
        AF.request(url).response { response in
            switch response.result {
            case .success(let data):
                if let priceString = String(data: data!, encoding: .utf8),
                   let price = Double(priceString) {
                    completion(price)
                } else {
                    completion(nil)
                }
            case .failure(_):
                completion(nil)
            }
        }
    }
}

